select count(1)
from reports

  and deleted = false

    and (target_title like concat('%', #{keyword}, '%') or reporter_name like concat('%', #{keyword}, '%'))


    and report_type = #{reportType}


    and status = #{status}

select report_id, report_type, target_id, target_title, reporter_name, status, report_time, handle_result, handle_remark,
       created_at, updated_at, created_by, updated_by, deleted
from reports

  and deleted = false

    and (target_title like concat('%', #{keyword}, '%') or reporter_name like concat('%', #{keyword}, '%'))


    and report_type = #{reportType}


    and status = #{status}


order by report_id asc
limit #{pageSize} offset #{offset}
